)  VALUES (#v_DOCID#, $v_ATTACHSN$, #v_ATTACHNAME#, #v_ATTACHDISPNAME#,    #v_ATTACHHREF#, $v_ATTACHSIZE$, #v_USERID#,    #v_USERNAME#,   #v_USERNAME2#,   #v_USERJOBTITLE#,   #v_USERJOBTITLE2#,    #v_USERDEPTID#, #v_USERDEPTNAME#,   #v_USERDEPTNAME2#,    TO_DATE(#v_SYSDATE# ,'YYYY-MM-DD HH24:MI:SS'), $v_MODIFYSN$, #v_MODIFYFLAG#, $v_PAGENUM$,  ' ' , $v_TENANTID$, #companyID#)

